CREATE TABLE orders (order_id UUID NOT NULL DEFAULT gen_random_uuid(), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), user_id UUID NOT NULL REFERENCES users(user_id), restaurant_id UUID NOT NULL REFERENCES restaurants(restaurant_id), address_id UUID REFERENCES addresses(address_id), status order_status NOT NULL DEFAULT 'order_created', subtotal DECIMAL(10,2) NOT NULL, taxes DECIMAL(10,2) NOT NULL, delivery_fee DECIMAL(10,2) NOT NULL, discount DECIMAL(10,2) NOT NULL DEFAULT 0, total_amount DECIMAL(10,2) NOT NULL, payment_method VARCHAR(20) NOT NULL, idempotency_key VARCHAR(64), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), PRIMARY KEY(order_id, created_at)) PARTITION BY RANGE (created_at);
CREATE TABLE orders_default PARTITION OF orders DEFAULT;
CREATE UNIQUE INDEX uq_orders_idempotency ON orders(idempotency_key) WHERE idempotency_key IS NOT NULL;
CREATE TABLE order_items (order_item_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, order_created_at TIMESTAMPTZ NOT NULL, item_id UUID NOT NULL REFERENCES menu_items(item_id), item_name_snapshot VARCHAR(200) NOT NULL, item_price_snapshot DECIMAL(10,2) NOT NULL, quantity SMALLINT NOT NULL, line_total DECIMAL(10,2) NOT NULL, FOREIGN KEY(order_id,order_created_at) REFERENCES orders(order_id,created_at) ON DELETE CASCADE);
CREATE TABLE order_status_history (history_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), order_id UUID NOT NULL, order_created_at TIMESTAMPTZ NOT NULL, from_status order_status, to_status order_status NOT NULL, changed_by UUID REFERENCES users(user_id), changed_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), FOREIGN KEY(order_id,order_created_at) REFERENCES orders(order_id,created_at) ON DELETE CASCADE);
